# app/mailers/application_mailer.rb
class ApplicationMailer < ActionMailer::Base
  default from: ENV['SENDGRID_FROM_EMAIL'] || 'noreply@example.com'
  layout 'mailer'
end

# app/mailers/user_mailer.rb
class UserMailer < ApplicationMailer
  def welcome_email(user)
    @user = user
    @url = root_url
    
    mail(
      to: email_address_with_name(@user.email, @user.name),
      subject: 'Welcome to Our Application',
      reply_to: ENV['SENDGRID_REPLY_TO_EMAIL']
    )
  end

  def notification_email(user, notification)
    @user = user
    @notification = notification
    
    mail(
      to: @user.email,
      subject: notification.subject,
      template_name: 'notification'
    )
  end

  def custom_email(recipient, subject, body, options = {})
    @body = body
    @custom_data = options[:custom_data]
    
    mail_options = {
      to: recipient,
      subject: subject
    }
    
    mail_options[:cc] = options[:cc] if options[:cc]
    mail_options[:bcc] = options[:bcc] if options[:bcc]
    mail_options[:reply_to] = options[:reply_to] if options[:reply_to]
    
    if options[:attachments]
      options[:attachments].each do |attachment|
        attachments[attachment[:filename]] = attachment[:content]
      end
    end
    
    if options[:headers]
      headers(options[:headers])
    end
    
    mail(mail_options)
  end

  def bulk_email(recipients, subject, body)
    @body = body
    
    mail(
      to: ENV['SENDGRID_FROM_EMAIL'],
      bcc: recipients,
      subject: subject
    )
  end
end

# app/mailers/concerns/sendgrid_headers.rb
module SendgridHeaders
  extend ActiveSupport::Concern

  def add_sendgrid_headers(options = {})
    headers['X-SMTPAPI'] = sendgrid_header_json(options).to_json
  end

  def sendgrid_header_json(options)
    header = {}
    
    header['category'] = options[:category] if options[:category]
    header['unique_args'] = options[:unique_args] if options[:unique_args]
    header['filters'] = options[:filters] if options[:filters]
    header['asm_group_id'] = options[:asm_group_id] if options[:asm_group_id]
    header['send_at'] = options[:send_at].to_i if options[:send_at]
    header['ip_pool'] = options[:ip_pool] if options[:ip_pool]
    
    header
  end
end

# app/mailers/transactional_mailer.rb
class TransactionalMailer < ApplicationMailer
  include SendgridHeaders

  def order_confirmation(order)
    @order = order
    @user = order.user
    
    add_sendgrid_headers(
      category: ['order_confirmation'],
      unique_args: {
        order_id: @order.id,
        user_id: @user.id
      }
    )
    
    mail(
      to: @user.email,
      subject: "Order Confirmation ##{@order.id}"
    )
  end

  def password_reset(user, token)
    @user = user
    @token = token
    @reset_url = edit_password_reset_url(@token, host: default_url_options[:host])
    
    add_sendgrid_headers(
      category: ['password_reset'],
      unique_args: { user_id: @user.id }
    )
    
    mail(
      to: @user.email,
      subject: 'Password Reset Instructions'
    )
  end

  def scheduled_email(user, content, send_at_time)
    @user = user
    @content = content
    
    add_sendgrid_headers(
      category: ['scheduled'],
      send_at: send_at_time,
      unique_args: { user_id: @user.id }
    )
    
    mail(
      to: @user.email,
      subject: 'Scheduled Notification'
    )
  end
end

# app/services/email_service.rb
class EmailService
  def self.send_welcome_email(user)
    begin
      UserMailer.welcome_email(user).deliver_now
      Rails.logger.info "Welcome email sent to #{user.email}"
      true
    rescue StandardError => e
      Rails.logger.error "Failed to send welcome email to #{user.email}: #{e.message}"
      false
    end
  end

  def self.send_welcome_email_async(user)
    UserMailer.welcome_email(user).deliver_later
  end

  def self.send_bulk_emails(recipients, subject, body)
    begin
      UserMailer.bulk_email(recipients, subject, body).deliver_now
      Rails.logger.info "Bulk email sent to #{recipients.count} recipients"
      true
    rescue StandardError => e
      Rails.logger.error "Failed to send bulk email: #{e.message}"
      false
    end
  end

  def self.send_with_attachment(recipient, subject, body, files)
    attachments = files.map do |file|
      {
        filename: file.original_filename,
        content: file.read
      }
    end

    UserMailer.custom_email(
      recipient,
      subject,
      body,
      attachments: attachments
    ).deliver_now
  end
end

