namespace :sendgrid do
  desc 'Test SendGrid configuration'
  task test: :environment do
    begin
      test_email = ENV['TEST_EMAIL'] || 'test@example.com'
      
      UserMailer.custom_email(
        test_email,
        'SendGrid Test Email',
        'This is a test email to verify SendGrid configuration.'
      ).deliver_now
      
      puts "Test email sent successfully to #{test_email}"
    rescue StandardError => e
      puts "Failed to send test email: #{e.message}"
      puts e.backtrace.join("\n")
    end
  end
