# app/jobs/email_job.rb
class EmailJob < ApplicationJob
  queue_as :mailers
  
  retry_on Net::SMTPServerBusy, wait: 5.seconds, attempts: 3
  retry_on Net::SMTPSyntaxError, wait: 5.seconds, attempts: 2
  
  def perform(mailer_class, mailer_method, *args)
    mailer_class.constantize.send(mailer_method, *args).deliver_now
  end
end

# config/initializers/sendgrid.rb
if Rails.env.development? || Rails.env.production?
  required_env_vars = ['SENDGRID_API_KEY', 'SENDGRID_FROM_EMAIL']
  
  missing_vars = required_env_vars.select { |var| ENV[var].blank? }
  
  if missing_vars.any? && Rails.env.production?
    raise "Missing required environment variables: #{missing_vars.join(', ')}"
  elsif missing_vars.any? && Rails.env.development?
    Rails.logger.warn "Missing SendGrid environment variables: #{missing_vars.join(', ')}"
  end
end

