# app/mailers/interceptors/development_email_interceptor.rb
class DevelopmentEmailInterceptor
  def self.delivering_email(message)
    message.subject = "[DEV] #{message.subject}"
    message.to = ENV['DEV_EMAIL_RECIPIENT'] if ENV['DEV_EMAIL_RECIPIENT'].present?
  end
end